let demoFlag = false;
const memStore = {};
function isDemo() { return demoFlag || !window.storage; }
function withTimeout(p, ms) {
  return Promise.race([p, new Promise((_, rej) => setTimeout(() => rej(new Error("timeout")), ms))]);
}
async function sGet(key, def) {
  if (!window.storage || demoFlag) return key in memStore ? memStore[key] : def;
  try {
    const r = await withTimeout(window.storage.get(key, true), 3000);
    return r ? JSON.parse(r.value) : def;
  } catch (e) {
    const m = String(e && e.message || e);
    if (/not.?found|404|exist/i.test(m)) return def;
    demoFlag = true;
    return key in memStore ? memStore[key] : def;
  }
}
async function sSet(key, val) {
  if (!window.storage || demoFlag) { memStore[key] = val; demoFlag = true; return; }
  try { await withTimeout(window.storage.set(key, JSON.stringify(val), true), 3000); }
  catch (e) { demoFlag = true; memStore[key] = val; }
}

/* ====== 图片压缩 ====== */
function compressImage(file, maxPx) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const img = new Image();
      img.onload = () => {
        const scale = Math.min(1, (maxPx || 900) / Math.max(img.width, img.height));
        const cv = document.createElement("canvas");
        cv.width = Math.round(img.width * scale);
        cv.height = Math.round(img.height * scale);
        cv.getContext("2d").drawImage(img, 0, 0, cv.width, cv.height);
        resolve(cv.toDataURL("image/jpeg", 0.7));
      };
      img.onerror = reject;
      img.src = reader.result;
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

/* ====== 马来西亚电话 → wa.me ====== */
function waPhone(p) {
  const d = String(p || "").replace(/\D/g, "");
  if (!d) return "";
  if (d.startsWith("60")) return d;
  if (d.startsWith("0")) return "60" + d.slice(1);
  return d;
}

