/* ====== 背景音乐 ====== */
let _audioEl = null;
function musicInit(url) {
  // 把 Google Drive /view 链接转成直链
  if (!url) return null;
  let src = url.trim();
  // Google Drive: 不支持直接播放, 返回原 url (会播放失败, 宾客看不到报错)
  // Dropbox: dl=0 → dl=1
  if (src.includes("dropbox.com")) src = src.replace("?dl=0","?dl=1").replace("www.dropbox.com","dl.dropboxusercontent.com");
  // Dropbox: ?dl=0 → ?dl=1
  src = src.replace(/dropbox\.com(.+)\?dl=0/, 'dropbox.com$1?dl=1');
  return src;
}
function musicPlay(url) {
  try {
    const src = musicInit(url);
    if (!src) return;
    if (!_audioEl) {
      _audioEl = new Audio();
      _audioEl.loop = true;
      _audioEl.volume = 0.35;
    }
    if (_audioEl.src !== src) {
      _audioEl.src = src;
      _audioEl.load();
    }
    _audioEl.play().catch(() => {}); // 忽略浏览器自动播放限制
  } catch (e) {}
}
function musicPause() {
  try { if (_audioEl) { _audioEl.pause(); _audioEl.currentTime = 0; } } catch (e) {}
}

function themeOf(setup) {
  if (setup.theme === "custom" && setup.customTheme) return setup.customTheme;
  return THEMES.find(t => t.id === setup.theme) || THEMES[0];
}
function fontOf(setup) { return (FONTS.find(f => f.id === setup.font) || FONTS[0]).css; }





/* ====== 可拖动调整位置的照片 ====== */
function DraggablePhoto({ src, pos, onPos, height, radius, hint }) {
  const ref = useRef(null);
  const drag = useRef(null);
  const start = (e) => {
    const t = e.touches ? e.touches[0] : e;
    drag.current = { sx: t.clientX, sy: t.clientY, ox: pos.x, oy: pos.y };
  };
  const move = (e) => {
    if (!drag.current || !ref.current) return;
    const t = e.touches ? e.touches[0] : e;
    const r = ref.current.getBoundingClientRect();
    const nx = drag.current.ox - ((t.clientX - drag.current.sx) / r.width) * 100;
    const ny = drag.current.oy - ((t.clientY - drag.current.sy) / r.height) * 100;
    onPos({ x: Math.max(0, Math.min(100, nx)), y: Math.max(0, Math.min(100, ny)) });
    if (e.cancelable) e.preventDefault();
  };
  const end = () => { drag.current = null; };
  return (
    <div className="relative">
      <div ref={ref}
        onMouseDown={start} onMouseMove={move} onMouseUp={end} onMouseLeave={end}
        onTouchStart={start} onTouchMove={move} onTouchEnd={end}
        style={{
          height, borderRadius: radius || 14, touchAction: "none", cursor: "grab",
          backgroundImage: `url(${src})`, backgroundSize: "cover",
          backgroundPosition: `${pos.x}% ${pos.y}%`,
        }} className="w-full" />
      {hint && (
        <div className="absolute bottom-2 left-1/2 -translate-x-1/2 px-3 py-1 rounded-full text-[10px] text-white pointer-events-none"
          style={{ background: "rgba(0,0,0,.45)" }}>↕↔ 拖动照片调整位置</div>
      )}
    </div>
  );
}

/* ====== 照片上传格 (文件 + 链接两种方式) ====== */
function PhotoSlot({ label, photo, onChange, height, line, soft, deep }) {
  const [msg, setMsg] = useState("");
  const pick = async (file) => {
    if (!file) return;
    setMsg("⏳ 处理中...");
    try {
      const src = await compressImage(file, 1100);
      onChange({ src, pos: { x: 50, y: 35 } });
      setMsg("");
    } catch (e) { setMsg("❌ 读不到这张图 (HEIC格式不支持, 请截图后再上传)"); }
  };
  return (
    <div className="mt-4 p-3 rounded-2xl" style={{ border: `1.5px dashed ${line}`, background: "#fffdfa" }}>
      <div className="flex items-center justify-between">
        <div className="text-[11px] font-bold tracking-widest" style={{ color: deep }}>{label}</div>
        {photo && <button onClick={() => onChange(null)} className="text-[11px] font-bold" style={{ color: "#c0564f" }}>✕ 移除</button>}
      </div>
      {photo ? (
        <div className="mt-2">
          <DraggablePhoto src={photo.src} pos={photo.pos} height={height} hint
            onPos={(pos) => onChange({ ...photo, pos })} />
        </div>
      ) : (
        <div className="mt-2">
          <input type="file" accept="image/png,image/jpeg,image/webp,image/*" className="block w-full text-xs"
            onChange={e => pick(e.target.files && e.target.files[0])} />
          <div className="flex gap-2 mt-2">
            <input type="url" placeholder="或贴图片链接 https://..." id={"url-" + label}
              className="flex-1 min-w-0 px-3 py-2 rounded-lg text-xs outline-none bg-white" style={{ border: `1px solid ${line}` }} />
            <button onClick={() => {
              const v = document.getElementById("url-" + label).value.trim();
              if (v) onChange({ src: v, pos: { x: 50, y: 35 } });
            }} className="shrink-0 px-3 py-2 rounded-lg text-[11px] font-bold text-white" style={{ background: deep }}>用链接</button>
          </div>
        </div>
      )}
      {msg && <div className="mt-2 text-[11px]" style={{ color: msg.startsWith("❌") ? "#a04540" : soft }}>{msg}</div>}
    </div>
  );
}


